{"content": "     1|import { notFound } from 'next/navigation';
     2|import Link from 'next/link';
     3|import { createClient } from '@/lib/supabase/server';
     4|import { ProductCard } from '@/components/store/product-card';
     5|import type { Product, KinkCategory } from '@/types/database';
     6|import type { Metadata } from 'next';
     7|
     8|interface Props {
     9|  params: Promise<{ slug: string }>;
