    11|
    12|export async function generateMetadata({ params }: Props): Promise<Metadata> {
    13|  const { slug } = await params;
    14|  const supabase = await createClient();
    15|  // eslint-disable-next-line @typescript-eslint/no-explicit-any
    16|  const { data: kinkData } = await (supabase as any)
    17|    .from('kink_categories')
    18|    .select('name, description')
    19|    .eq('slug', slug)
    20|    .single();
    21|
    22|  if (!kinkData) return { title: 'Kink no encontrado' };
    23|  const k = kinkData as { name: string; description: string | null };
    24|
    25|  return {
    26|    title: `${k.name} | Fun4Me Store`,
    27|    description: k.description || `Explorá productos de ${k.name}`,
    28|  };
