    54|  let products: (Product & { categories: { slug: string } | null })[] = [];
    55|  if (productIds.length > 0) {
    56|    const { data } = await supabase
    57|      .from('products')
    58|      .select('*, categories(slug)')
    59|      .in('id', productIds)
    60|      .eq('is_active', true)
    61|      .order('is_featured', { ascending: false });
    62|    products = (data || []) as (Product & { categories: { slug: string } | null })[];
    63|  }
    64|
    65|  return (
    66|    <div className="container mx-auto px-4 py-8">
