    72|        <span>/</span>
    73|        <span className="text-foreground">{kinkCat.name}</span>
    74|      </nav>
    75|
    76|      {/* Kink Header */}
    77|      <div className="mb-10 rounded-2xl bg-gradient-to-r from-orange-50 to-rose-50 p-8">
    78|        <div className="flex items-center gap-3">
    79|          <span className="text-4xl">🔥</span>
    80|          <h1 className="text-3xl font-bold">{kinkCat.name}</h1>
    81|        </div>
    82|        {kinkCat.description && (
    83|          <p className="mt-4 max-w-2xl text-muted-foreground leading-relaxed">
    84|            {kinkCat.description}
    85|          </p>
    86|        )}
    87|        <p className="mt-3 text-sm text-muted-foreground">
    88|          💡 Recordá que la comunicación con tu pareja es clave. Todos los productos son seleccionados pensando en tu seguridad y bienestar.
    89|        </p>
    90|      </div>
    91|
    92|      <p className="mb-6 text-sm text-muted-foreground">{products.length} productos</p>
    93|
