    19|  accesorios: 'from-teal-400 to-emerald-500',
    20|  default: 'from-rose-400 to-purple-500',
    21|};
    22|
    23|const LEVEL_BADGES: Record<string, { emoji: string; label: string }> = {
    24|  principiante: { emoji: '🟢', label: 'Principiante' },
    25|  intermedio: { emoji: '🟡', label: 'Intermedio' },
    26|  avanzado: { emoji: '🔴', label: 'Avanzado' },
