    36|    is_featured: boolean;
    37|    experience_level?: string | null;
    38|    category_slug?: string;
    39|  };
    40|}
    41|
    42|export function ProductCard({ product }: ProductCardProps) {
    43|  const addItem = useCartStore((s) => s.addItem);
    44|  const gradient = CATEGORY_GRADIENTS[product.category_slug || 'default'] || CATEGORY_GRADIENTS.default;
    45|  const level = product.experience_level
    46|    ? LEVEL_BADGES[product.experience_level.toLowerCase()]
    47|    : null;
    48|  const hasDiscount = product.compare_at_price && product.compare_at_price > product.price;
    49|  const discountPct = hasDiscount
    50|    ? Math.round(((product.compare_at_price! - product.price) / product.compare_at_price!) * 100)
